VALUES
  ('optician-moex-01949', 'optician', 'optician-moex-108-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '當操作角膜弧度儀（keratometry）為患者量測角膜屈光度，假如患者角膜曲率半徑很大，已超出儀器可量 測角膜屈光度數範圍（36.00 D ~ 52.00 D），則此時可以在角膜弧度儀前，面向患者眼睛處置入何種試鏡 片（trail lens）來輔助量測，以測得患者正確角膜屈光度？', '["置入+1.25 DS，以縮減大約9.00 DS範圍", "置入+1.00 DS，以縮減大約6.00 DS範圍", "置入-1.25 DS，以擴增大約9.00 DS範圍", "置入-1.00 DS，以縮減大約6.00 DS範圍"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "b5729e769b59", "answer_pdf_sha1": "e88e08bae45b", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "402", "s": "0807", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
